import React, { useEffect, useState } from "react";
import axios from "axios";

export default function Categorias() {
  const [categorias, setCategorias] = useState([]);
  const [productos, setProductos] = useState([]);
  const [categoriaSeleccionada, setCategoriaSeleccionada] = useState(null);
  const [cargando, setCargando] = useState(false);

  // --- Modal Agregar Categoría ---
  const [mostrarModal, setMostrarModal] = useState(false);
  const [nuevaCategoria, setNuevaCategoria] = useState({ nombre: "", descripcion: "" });
  const [guardando, setGuardando] = useState(false);

  // --- Modal Editar Categoría ---
  const [categoriaEditando, setCategoriaEditando] = useState({ id: "", nombre: "", descripcion: "" });
  const [mostrarModalEditarCategoria, setMostrarModalEditarCategoria] = useState(false);

  // --- Modal Editar Producto ---
  const [mostrarModalProducto, setMostrarModalProducto] = useState(false);
  const [productoEditando, setProductoEditando] = useState({ id: "", nombre: "", precio: "", stock: "" });
  const [guardandoProducto, setGuardandoProducto] = useState(false);

  useEffect(() => {
    obtenerCategorias();
  }, []);

  const obtenerCategorias = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/categorias");
      setCategorias(res.data);
    } catch (error) {
      console.error("❌ Error al obtener categorías:", error);
    }
  };

  const mostrarProductosPorCategoria = async (categoria) => {
    setCategoriaSeleccionada(categoria);
    setCargando(true);
    try {
      const res = await axios.get(`http://localhost:5000/api/productos/categoria/${categoria.id}`);
      setProductos(res.data);
    } catch (error) {
      console.error("❌ Error al obtener productos:", error);
    } finally {
      setCargando(false);
    }
  };

  const volverACategorias = () => {
    setCategoriaSeleccionada(null);
    setProductos([]);
  };

  // --- Agregar Categoría ---
  const handleAbrirModal = () => {
    setNuevaCategoria({ nombre: "", descripcion: "" });
    setMostrarModal(true);
  };

  const handleCerrarModal = () => setMostrarModal(false);

  const handleGuardarCategoria = async (e) => {
    e.preventDefault();
    setGuardando(true);
    try {
      await axios.post("http://localhost:5000/api/categorias", nuevaCategoria);
      await obtenerCategorias();
      setMostrarModal(false);
    } catch (error) {
      console.error("❌ Error al guardar categoría:", error);
      alert("Error al guardar la categoría");
    } finally {
      setGuardando(false);
    }
  };

  // --- Editar Categoría ---
  const abrirModalEditarCategoria = (cat) => {
    setCategoriaEditando(cat);
    setMostrarModalEditarCategoria(true);
  };

  const handleGuardarCategoriaEditada = async (e) => {
    e.preventDefault();
    try {
      await axios.put(`http://localhost:5000/api/categorias/${categoriaEditando.id}`, categoriaEditando);
      await obtenerCategorias();
      setMostrarModalEditarCategoria(false);
      alert("✅ Categoría actualizada correctamente");
    } catch (error) {
      console.error("❌ Error al actualizar categoría:", error);
      alert("Error al actualizar categoría");
    }
  };

  // --- Eliminar Categoría ---
  const eliminarCategoria = async (id) => {
    if (!window.confirm("¿Seguro que deseas eliminar esta categoría?")) return;
    try {
      await axios.delete(`http://localhost:5000/api/categorias/${id}`);
      alert("🗑️ Categoría eliminada correctamente");
      if (categoriaSeleccionada?.id === id) volverACategorias();
      await obtenerCategorias();
    } catch (error) {
      console.error("❌ Error al eliminar categoría:", error);
      alert("Error al eliminar categoría");
    }
  };

  // --- Editar Producto ---
  const abrirModalEditarProducto = (producto) => {
    setProductoEditando(producto);
    setMostrarModalProducto(true);
  };

  const cerrarModalProducto = () => setMostrarModalProducto(false);

  const handleGuardarProducto = async (e) => {
    e.preventDefault();
    setGuardandoProducto(true);
    try {
      await axios.put(`http://localhost:5000/api/productos/${productoEditando.id}`, productoEditando);
      alert("✅ Producto actualizado correctamente");
      await mostrarProductosPorCategoria(categoriaSeleccionada);
      setMostrarModalProducto(false);
    } catch (error) {
      console.error("❌ Error al actualizar producto:", error);
      alert("Error al actualizar el producto");
    } finally {
      setGuardandoProducto(false);
    }
  };

  const eliminarProducto = async (id) => {
    if (!window.confirm("¿Seguro que deseas eliminar este producto?")) return;
    try {
      await axios.delete(`http://localhost:5000/api/productos/${id}`);
      alert("🗑️ Producto eliminado correctamente");
      await mostrarProductosPorCategoria(categoriaSeleccionada);
    } catch (error) {
      console.error("❌Hay Produtos en la categoria no la puedes eliminar", error);
      alert("Error al eliminar producto");
    }
  };

  return (
    <div className="container mt-5 position-relative">
      {!categoriaSeleccionada ? (
        <>
          <div className="d-flex justify-content-between align-items-center mb-4">
            <h2 className="fw-bold">Categorías</h2>
          </div>

          <div className="row justify-content-center">
            {categorias.length > 0 ? (
              categorias.map((cat) => (
                <div key={cat.id} className="col-10 col-md-4 col-lg-3 mb-4">
                  <div className="card shadow-lg border-0 text-center p-4 bg-light position-relative">
                    <h4
                      className="fw-bold text-primary"
                      style={{ cursor: "pointer" }}
                      onClick={() => mostrarProductosPorCategoria(cat)}
                    >
                      {cat.nombre}
                    </h4>
                    <p className="text-muted small mb-3">
                      {cat.descripcion || "Sin descripción"}
                    </p>

                    {/* Botones Editar y Eliminar categoría */}
                    <div className="d-flex justify-content-center gap-2">
                      <button
                        className="btn btn-warning btn-sm"
                        onClick={() => abrirModalEditarCategoria(cat)}
                      >
                        ✏️ Editar
                      </button>
                      <button
                        className="btn btn-danger btn-sm"
                        onClick={() => eliminarCategoria(cat.id)}
                      >
                        🗑️ Eliminar
                      </button>
                    </div>
                  </div>
                </div>
              ))
            ) : (
              <p className="text-center text-muted">No hay categorías registradas.</p>
            )}
          </div>

          {/* Botón flotante Agregar categoría */}
          <button
            className="btn btn-success rounded-circle shadow-lg position-fixed"
            style={{ bottom: "30px", right: "30px", width: "60px", height: "60px", fontSize: "24px" }}
            onClick={handleAbrirModal}
          >
            ➕
          </button>
        </>
      ) : (
        <>
          <div className="d-flex justify-content-between align-items-center mb-4">
            <h3 className="fw-bold">
              Productos en “{categoriaSeleccionada.nombre}”
            </h3>
            <button className="btn btn-outline-secondary" onClick={volverACategorias}>
              ← Volver
            </button>
          </div>

          {cargando ? (
            <p className="text-center text-muted">Cargando productos...</p>
          ) : productos.length > 0 ? (
            <div className="table-responsive">
              <table className="table table-bordered text-center align-middle">
                <thead className="table-dark">
                  <tr>
                    <th>ID</th>
                    <th>Nombre</th>
                    <th>Precio</th>
                    <th>Stock</th>
                    <th>Acciones</th>
                  </tr>
                </thead>
                <tbody>
                  {productos.map((p) => (
                    <tr key={p.id}>
                      <td>{p.id}</td>
                      <td>{p.nombre}</td>
                      <td>${p.precio}</td>
                      <td>{p.stock}</td>
                      <td>
                        <button
                          className="btn btn-warning btn-sm me-2"
                          onClick={() => abrirModalEditarProducto(p)}
                        >
                          ✏️ Editar
                        </button>
                        <button
                          className="btn btn-danger btn-sm"
                          onClick={() => eliminarProducto(p.id)}
                        >
                          🗑️ Eliminar
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          ) : (
            <p className="text-center text-muted">No hay productos en esta categoría.</p>
          )}
        </>
      )}

      {/* Modal Agregar Categoría */}
      {mostrarModal && (
        <div className="modal fade show d-block" style={{ background: "rgba(0,0,0,0.5)" }}>
          <div className="modal-dialog">
            <div className="modal-content shadow">
              <div className="modal-header">
                <h5 className="modal-title">Agregar nueva categoría</h5>
                <button type="button" className="btn-close" onClick={handleCerrarModal}></button>
              </div>
              <form onSubmit={handleGuardarCategoria}>
                <div className="modal-body">
                  <div className="mb-3">
                    <label className="form-label">Nombre</label>
                    <input
                      type="text"
                      className="form-control"
                      value={nuevaCategoria.nombre}
                      onChange={(e) => setNuevaCategoria({ ...nuevaCategoria, nombre: e.target.value })}
                      required
                    />
                  </div>
                  <div className="mb-3">
                    <label className="form-label">Descripción</label>
                    <textarea
                      className="form-control"
                      value={nuevaCategoria.descripcion}
                      onChange={(e) => setNuevaCategoria({ ...nuevaCategoria, descripcion: e.target.value })}
                      rows="3"
                    ></textarea>
                  </div>
                </div>
                <div className="modal-footer">
                  <button type="button" className="btn btn-secondary" onClick={handleCerrarModal}>
                    Cancelar
                  </button>
                  <button type="submit" className="btn btn-primary" disabled={guardando}>
                    {guardando ? "Guardando..." : "Guardar"}
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}

      {/* Modal Editar Categoría */}
      {mostrarModalEditarCategoria && (
        <div className="modal fade show d-block" style={{ background: "rgba(0,0,0,0.5)" }}>
          <div className="modal-dialog">
            <div className="modal-content shadow">
              <div className="modal-header">
                <h5 className="modal-title">Editar categoría</h5>
                <button type="button" className="btn-close" onClick={() => setMostrarModalEditarCategoria(false)}></button>
              </div>
              <form onSubmit={handleGuardarCategoriaEditada}>
                <div className="modal-body">
                  <div className="mb-3">
                    <label className="form-label">Nombre</label>
                    <input
                      type="text"
                      className="form-control"
                      value={categoriaEditando.nombre}
                      onChange={(e) => setCategoriaEditando({ ...categoriaEditando, nombre: e.target.value })}
                      required
                    />
                  </div>
                  <div className="mb-3">
                    <label className="form-label">Descripción</label>
                    <textarea
                      className="form-control"
                      value={categoriaEditando.descripcion}
                      onChange={(e) => setCategoriaEditando({ ...categoriaEditando, descripcion: e.target.value })}
                      rows="3"
                    ></textarea>
                  </div>
                </div>
                <div className="modal-footer">
                  <button type="button" className="btn btn-secondary" onClick={() => setMostrarModalEditarCategoria(false)}>
                    Cancelar
                  </button>
                  <button type="submit" className="btn btn-primary">
                    Guardar cambios
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}

      {/* Modal Editar Producto */}
      {mostrarModalProducto && (
        <div className="modal fade show d-block" style={{ background: "rgba(0,0,0,0.5)" }}>
          <div className="modal-dialog">
            <div className="modal-content shadow">
              <div className="modal-header">
                <h5 className="modal-title">Editar producto</h5>
                <button type="button" className="btn-close" onClick={cerrarModalProducto}></button>
              </div>
              <form onSubmit={handleGuardarProducto}>
                <div className="modal-body">
                  <div className="mb-3">
                    <label className="form-label">Nombre</label>
                    <input
                      type="text"
                      className="form-control"
                      value={productoEditando.nombre}
                      onChange={(e) => setProductoEditando({ ...productoEditando, nombre: e.target.value })}
                      required
                    />
                  </div>
                  <div className="mb-3">
                    <label className="form-label">Precio</label>
                    <input
                      type="number"
                      className="form-control"
                      value={productoEditando.precio}
                      onChange={(e) => setProductoEditando({ ...productoEditando, precio: e.target.value })}
                      required
                    />
                  </div>
                  <div className="mb-3">
                    <label className="form-label">Stock</label>
                    <input
                      type="number"
                      className="form-control"
                      value={productoEditando.stock}
                      onChange={(e) => setProductoEditando({ ...productoEditando, stock: e.target.value })}
                      required
                    />
                  </div>
                </div>
                <div className="modal-footer">
                  <button type="button" className="btn btn-secondary" onClick={cerrarModalProducto}>
                    Cancelar
                  </button>
                  <button type="submit" className="btn btn-primary" disabled={guardandoProducto}>
                    {guardandoProducto ? "Guardando..." : "Guardar cambios"}
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
